class Solution:
    def numComponents(self, head, nums):
        target = set(nums)
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        count = 0
        i = 0
        n = len(vals)
        while i < n:
            if vals[i] in target:
                while i < n and vals[i] in target:
                    i += 1
                count += 1
            else:
                i += 1
        return count

