var numComponents = function(head, nums) {
    const target = new Set(nums);
    let count = 0;
    let node = head;
    while (node) {
        if (target.has(node.val) && (node.next === null || !target.has(node.next.val))) {
            count++;
        }
        node = node.next;
    }
    return count;
};
